// Ported verbatim from the approved Claude Design file (rolligan.html).
// Shared base CSS + page styles inlined; dev panel/scripts stripped;
// reveal hiding neutralized; nav .html links rewritten to routes.
const STYLE = "@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800;900&family=Geist+Mono:wght@400;500&display=swap');\n\n  :root {\n    /* DEFAULTS \u2014 tweaks panel overrides --accent at runtime */\n    --accent: #3b3eed;\n    --accent-2: #6366f1;\n    --accent-soft: #eef0ff;\n    --accent-ink: #1e1b8c;\n\n    --bg: #ffffff;\n    --bg-2: #f7f7f9;\n    --bg-3: #fafafb;\n    --ink: #1d1d1f;\n    --ink-2: #2c2c2e;\n    --ink-3: #424245;\n    --mute: #6e6e73;\n    --line: #e8e8ed;\n    --line-2: #d2d2d7;\n    --dark: #0b0b10;\n    --dark-2: #14141a;\n    --dark-line: rgba(255,255,255,0.08);\n    --on-dark: #f5f5f7;\n    --on-dark-mute: #a1a1a6;\n  }\n\n  *, *::before, *::after { box-sizing: border-box; }\n  html, body { margin: 0; padding: 0; background: var(--bg); color: var(--ink); }\n  body {\n    font-family: 'SF Pro Display', -apple-system, BlinkMacSystemFont, 'Inter', system-ui, sans-serif;\n    font-size: 17px; line-height: 1.47;\n    letter-spacing: -0.012em;\n    font-weight: 400;\n    -webkit-font-smoothing: antialiased;\n    text-rendering: optimizeLegibility;\n  }\n  ::selection { background: var(--accent); color: #fff; }\n  a { color: inherit; text-decoration: none; }\n  img { display: block; max-width: 100%; }\n\n  /* \u2500\u2500\u2500 TYPE \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n  h1, h2, h3, h4 { margin: 0; font-weight: 700; letter-spacing: -0.03em; line-height: 1.02; }\n  h1 { font-size: clamp(72px, 10vw, 144px); font-weight: 800; letter-spacing: -0.045em; }\n  h2 { font-size: clamp(48px, 5.6vw, 84px); font-weight: 700; letter-spacing: -0.035em; }\n  h3 { font-size: clamp(28px, 2.6vw, 40px); font-weight: 600; letter-spacing: -0.025em; }\n  h4 { font-size: 22px; font-weight: 600; letter-spacing: -0.018em; }\n  p { margin: 0; }\n  .display { font-weight: 800; letter-spacing: -0.04em; }\n  .lede { font-size: clamp(20px, 1.8vw, 26px); line-height: 1.36; color: var(--ink-3); font-weight: 400; letter-spacing: -0.013em; max-width: 34ch; }\n  .body { font-size: 17px; line-height: 1.55; color: var(--ink-3); max-width: 60ch; }\n  .body-sm { font-size: 14.5px; line-height: 1.55; color: var(--mute); }\n  .eyebrow {\n    display: inline-flex; align-items: center; gap: 8px;\n    font-size: 13px; font-weight: 500; letter-spacing: -0.005em;\n    color: var(--accent);\n  }\n  .eyebrow .dot { width: 6px; height: 6px; border-radius: 50%; background: var(--accent); box-shadow: 0 0 0 4px var(--accent-soft); }\n  .micro { font-family: 'Geist Mono', ui-monospace, 'SF Mono', monospace; font-size: 11.5px; letter-spacing: 0.06em; text-transform: uppercase; color: var(--mute); }\n  .num { font-variant-numeric: tabular-nums lining-nums; font-feature-settings: \"tnum\",\"lnum\"; }\n\n  /* \u2500\u2500\u2500 CONTAINERS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n  .container { max-width: 1240px; margin: 0 auto; padding: 0 32px; }\n  .container-narrow { max-width: 1024px; margin: 0 auto; padding: 0 32px; }\n  .container-tight { max-width: 880px; margin: 0 auto; padding: 0 32px; }\n  .hairline { height: 1px; background: var(--line); border: 0; margin: 0; }\n\n  /* \u2500\u2500\u2500 NAV \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n  .topbar {\n    background: var(--bg-2);\n    text-align: center;\n    padding: 11px 24px;\n    font-size: 13.5px; color: var(--ink-3);\n    border-bottom: 1px solid var(--line);\n  }\n  .topbar strong { color: var(--ink); font-weight: 600; }\n  .topbar a { color: var(--accent); font-weight: 500; }\n  .topbar a:hover { text-decoration: underline; }\n\n  nav.primary {\n    position: sticky; top: 0; z-index: 50;\n    background: rgba(255,255,255,0.78);\n    -webkit-backdrop-filter: saturate(180%) blur(24px);\n    backdrop-filter: saturate(180%) blur(24px);\n    border-bottom: 1px solid rgba(0,0,0,0.06);\n  }\n  nav.primary .container {\n    height: 56px; display: flex; align-items: center; justify-content: space-between;\n  }\n  .wordmark {\n    display: inline-flex; align-items: baseline; gap: 0;\n    font-size: 19px; font-weight: 700; letter-spacing: -0.025em; color: var(--ink);\n  }\n  .wordmark .dot {\n    width: 9px; height: 9px; background: var(--accent); border-radius: 2px;\n    display: inline-block; margin-left: 4px; transform: translateY(-1px);\n  }\n  nav.primary .links { display: flex; gap: 32px; }\n  nav.primary .links a {\n    font-size: 14px; color: var(--ink-3); font-weight: 500; transition: color .2s ease;\n  }\n  nav.primary .links a:hover { color: var(--ink); }\n  nav.primary .links a.active { color: var(--ink); }\n  nav.primary .nav-cta { display: flex; align-items: center; gap: 14px; }\n  nav.primary .nav-cta .sign { font-size: 14px; color: var(--ink-3); }\n  nav.primary .nav-cta .sign:hover { color: var(--ink); }\n\n  /* \u2500\u2500\u2500 BUTTONS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n  .btn {\n    display: inline-flex; align-items: center; justify-content: center; gap: 8px;\n    padding: 14px 22px; border-radius: 999px;\n    font-size: 15px; font-weight: 500; letter-spacing: -0.005em;\n    transition: transform .2s ease, background .2s ease, box-shadow .2s ease, opacity .2s ease;\n    border: 1px solid transparent;\n    cursor: pointer;\n  }\n  .btn-fill { background: var(--accent); color: #fff; box-shadow: 0 1px 0 rgba(255,255,255,0.1) inset, 0 8px 18px -8px var(--accent); }\n  .btn-fill:hover { transform: translateY(-1px); box-shadow: 0 1px 0 rgba(255,255,255,0.1) inset, 0 12px 24px -8px var(--accent); }\n  .btn-ghost { background: var(--bg-2); color: var(--ink); border-color: var(--line); }\n  .btn-ghost:hover { background: var(--bg); border-color: var(--line-2); }\n  .btn-dark { background: var(--ink); color: #fff; }\n  .btn-dark:hover { background: var(--ink-2); transform: translateY(-1px); }\n  .btn-sm { padding: 10px 16px; font-size: 13.5px; }\n  .link-arrow { display: inline-flex; align-items: center; gap: 6px; color: var(--accent); font-weight: 500; font-size: 15px; }\n  .link-arrow .ch { transition: transform .25s ease; }\n  .link-arrow:hover .ch { transform: translateX(4px); }\n\n  /* \u2500\u2500\u2500 HERO \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n  .hero { position: relative; padding: 88px 0 56px; overflow: hidden; }\n  .hero .container { text-align: center; position: relative; z-index: 2; }\n  .hero .badge {\n    display: inline-flex; align-items: center; gap: 8px;\n    padding: 6px 14px; border-radius: 999px;\n    background: var(--accent-soft);\n    color: var(--accent);\n    font-size: 13.5px; font-weight: 500; letter-spacing: -0.005em;\n    margin-bottom: 28px;\n    border: 1px solid color-mix(in srgb, var(--accent) 25%, transparent);\n  }\n  .hero .badge .dot { width: 7px; height: 7px; border-radius: 50%; background: var(--accent); position: relative; }\n  .hero .badge .dot::after {\n    content: ''; position: absolute; inset: -3px; border-radius: 50%;\n    background: var(--accent); opacity: 0.4; animation: ping 2.4s ease-out infinite;\n  }\n  .hero h1 { max-width: 14ch; margin: 0 auto; color: var(--ink); }\n  .hero h1 .stop { color: var(--accent); }\n  .hero .sub {\n    margin: 28px auto 36px;\n    max-width: 640px;\n    font-size: 22px; line-height: 1.45; color: var(--ink-3);\n    font-weight: 400; letter-spacing: -0.012em;\n  }\n  .hero .ctas { display: flex; gap: 12px; justify-content: center; margin-bottom: 16px; }\n  .hero .ribbon {\n    display: inline-flex; gap: 14px; padding: 10px 18px; border-radius: 999px;\n    background: var(--bg-2); border: 1px solid var(--line);\n    font-size: 13px; color: var(--mute); font-weight: 500;\n    margin-top: 28px;\n  }\n  .hero .ribbon .sep { color: var(--line-2); }\n  /* hero glow */\n  .hero::before {\n    content: ''; position: absolute; left: 50%; top: -100px; width: 1000px; height: 600px;\n    transform: translateX(-50%);\n    background: radial-gradient(50% 50% at 50% 50%, color-mix(in srgb, var(--accent) 16%, transparent) 0%, transparent 65%);\n    pointer-events: none; z-index: 1;\n  }\n\n  /* \u2500\u2500\u2500 DICE (the hero object) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n  .stage {\n    margin: 56px auto 0;\n    position: relative; width: 100%; max-width: 980px;\n    height: 460px;\n    display: flex; align-items: flex-end; justify-content: center;\n  }\n  .die-stack { position: relative; width: 720px; height: 360px; }\n  .die {\n    position: absolute;\n    border-radius: 32px;\n    background:\n      linear-gradient(160deg, #ffffff 0%, #fafafb 50%, #ececf0 100%);\n    box-shadow:\n      0 2px 0 rgba(255,255,255,1) inset,\n      0 -2px 0 rgba(0,0,0,0.04) inset,\n      0 24px 32px -8px rgba(20,22,40,0.12),\n      0 60px 80px -20px rgba(20,22,40,0.22);\n    padding: 28px;\n    display: grid;\n    grid-template-columns: repeat(3, 1fr);\n    grid-template-rows: repeat(3, 1fr);\n    border: 1px solid rgba(255,255,255,0.6);\n  }\n  .die .pip {\n    width: 24px; height: 24px; align-self: center; justify-self: center;\n    border-radius: 50%;\n    background:\n      radial-gradient(circle at 35% 30%, color-mix(in srgb, var(--accent) 90%, #000 0%) 0%, color-mix(in srgb, var(--accent) 60%, #000 35%) 80%);\n    box-shadow:\n      inset 0 1px 1px rgba(255,255,255,0.4),\n      inset 0 -1px 2px rgba(0,0,0,0.25),\n      0 1px 1px rgba(255,255,255,0.6);\n  }\n  .die.ink {\n    background: linear-gradient(160deg, #2a2a30 0%, #1c1c22 50%, #0b0b10 100%);\n    border: 1px solid rgba(255,255,255,0.06);\n  }\n  .die.ink .pip {\n    background: radial-gradient(circle at 35% 30%, #fff 0%, #d2d2d7 80%);\n    box-shadow: inset 0 1px 1px rgba(255,255,255,0.8), inset 0 -1px 2px rgba(0,0,0,0.3);\n  }\n  .die.accent {\n    background: linear-gradient(160deg, color-mix(in srgb, var(--accent) 70%, #fff) 0%, var(--accent) 60%, color-mix(in srgb, var(--accent) 70%, #000) 100%);\n    border: 1px solid color-mix(in srgb, var(--accent) 50%, #fff);\n    box-shadow:\n      0 2px 0 rgba(255,255,255,0.3) inset,\n      0 -2px 0 rgba(0,0,0,0.1) inset,\n      0 24px 40px -8px color-mix(in srgb, var(--accent) 35%, transparent),\n      0 60px 80px -20px color-mix(in srgb, var(--accent) 35%, transparent);\n  }\n  .die.accent .pip {\n    background: radial-gradient(circle at 35% 30%, #ffffff 0%, color-mix(in srgb, var(--accent) 10%, #fff) 80%);\n    box-shadow: inset 0 1px 1px rgba(255,255,255,0.9);\n  }\n\n  /* pip layouts via classes on .die */\n  .die.f5 .pip:nth-child(1) { grid-area: 1 / 1; } /* tl */\n  .die.f5 .pip:nth-child(2) { grid-area: 1 / 3; } /* tr */\n  .die.f5 .pip:nth-child(3) { grid-area: 2 / 2; } /* c */\n  .die.f5 .pip:nth-child(4) { grid-area: 3 / 1; } /* bl */\n  .die.f5 .pip:nth-child(5) { grid-area: 3 / 3; } /* br */\n  .die.f3 .pip:nth-child(1) { grid-area: 1 / 1; }\n  .die.f3 .pip:nth-child(2) { grid-area: 2 / 2; }\n  .die.f3 .pip:nth-child(3) { grid-area: 3 / 3; }\n  .die.f6 .pip:nth-child(1) { grid-area: 1 / 1; }\n  .die.f6 .pip:nth-child(2) { grid-area: 1 / 3; }\n  .die.f6 .pip:nth-child(3) { grid-area: 2 / 1; }\n  .die.f6 .pip:nth-child(4) { grid-area: 2 / 3; }\n  .die.f6 .pip:nth-child(5) { grid-area: 3 / 1; }\n  .die.f6 .pip:nth-child(6) { grid-area: 3 / 3; }\n  .die.f2 .pip:nth-child(1) { grid-area: 1 / 1; }\n  .die.f2 .pip:nth-child(2) { grid-area: 3 / 3; }\n\n  /* sizes and positions */\n  .die.size-lg { width: 280px; height: 280px; }\n  .die.size-md { width: 200px; height: 200px; padding: 24px; }\n  .die.size-md .pip { width: 20px; height: 20px; }\n  .die.size-sm { width: 150px; height: 150px; padding: 20px; }\n  .die.size-sm .pip { width: 16px; height: 16px; }\n\n  .die.pos-a { left: 50%; bottom: 30px; transform: translateX(-50%); animation: float-a 6s ease-in-out infinite; }\n  .die.pos-b { left: 12%; bottom: 60px; transform: rotate(-12deg); animation: float-b 7s ease-in-out infinite .4s; }\n  .die.pos-c { right: 12%; bottom: 70px; transform: rotate(11deg); animation: float-c 7.5s ease-in-out infinite .8s; }\n  .die.pos-d { left: 28%; bottom: 0; transform: rotate(-5deg); animation: float-d 8s ease-in-out infinite .2s; opacity: 0.85; }\n  .die.pos-e { right: 28%; bottom: 5px; transform: rotate(7deg); animation: float-e 8s ease-in-out infinite .6s; opacity: 0.85; }\n\n  .stage-shadow {\n    position: absolute; left: 50%; bottom: 4px; transform: translateX(-50%);\n    width: 580px; height: 24px;\n    background: radial-gradient(ellipse, rgba(20,22,40,0.22) 0%, transparent 70%);\n    filter: blur(6px);\n  }\n  .stage-floor {\n    position: absolute; left: 0; right: 0; bottom: 0; height: 1px; background: linear-gradient(90deg, transparent, var(--line), transparent);\n  }\n\n  @keyframes float-a {\n    0%, 100% { transform: translateX(-50%) translateY(0) rotate(0deg); }\n    50% { transform: translateX(-50%) translateY(-14px) rotate(2deg); }\n  }\n  @keyframes float-b {\n    0%, 100% { transform: rotate(-12deg) translateY(0); }\n    50% { transform: rotate(-14deg) translateY(-10px); }\n  }\n  @keyframes float-c {\n    0%, 100% { transform: rotate(11deg) translateY(0); }\n    50% { transform: rotate(13deg) translateY(-10px); }\n  }\n  @keyframes float-d {\n    0%, 100% { transform: rotate(-5deg) translateY(0); }\n    50% { transform: rotate(-7deg) translateY(-6px); }\n  }\n  @keyframes float-e {\n    0%, 100% { transform: rotate(7deg) translateY(0); }\n    50% { transform: rotate(9deg) translateY(-7px); }\n  }\n  @keyframes ping {\n    0% { transform: scale(1); opacity: 0.4; }\n    80%, 100% { transform: scale(2.4); opacity: 0; }\n  }\n\n  /* \u2500\u2500\u2500 SECTION rhythm \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n  .section { padding: 120px 0; }\n  .section-tight { padding: 80px 0; }\n  .section.alt { background: var(--bg-2); border-top: 1px solid var(--line); border-bottom: 1px solid var(--line); }\n  .section-head { text-align: center; margin-bottom: 64px; }\n  .section-head .eyebrow { margin-bottom: 16px; }\n  .section-head h2 { max-width: 18ch; margin: 0 auto; }\n  .section-head .sub { margin: 24px auto 0; max-width: 580px; color: var(--ink-3); font-size: 19px; line-height: 1.5; }\n  .section-head h2 .stop { color: var(--accent); }\n\n  /* \u2500\u2500\u2500 FEATURED ROLLIGAN BLOCK \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n  .feature-rolligan { padding: 56px 0 120px; position: relative; }\n  .feature-rolligan .meta-card {\n    margin: 0 auto;\n    max-width: 980px;\n    background: var(--bg);\n    border: 1px solid var(--line);\n    border-radius: 28px;\n    overflow: hidden;\n    box-shadow: 0 30px 60px -30px rgba(20,22,40,0.18);\n  }\n  .feature-rolligan .meta-card .top {\n    background: linear-gradient(180deg, var(--bg-2) 0%, var(--bg-3) 100%);\n    padding: 56px 40px 32px;\n    text-align: center;\n    border-bottom: 1px solid var(--line);\n    position: relative;\n    overflow: hidden;\n  }\n  .feature-rolligan .meta-card .top::before {\n    content: ''; position: absolute; left: 50%; top: -40px;\n    width: 600px; height: 200px;\n    transform: translateX(-50%);\n    background: radial-gradient(50% 50% at 50% 50%, color-mix(in srgb, var(--accent) 14%, transparent), transparent);\n    pointer-events: none;\n  }\n  .feature-rolligan .meta-card .top .stage {\n    height: 320px; max-width: 720px; margin: 24px auto 0;\n  }\n  .feature-rolligan .meta-card .top .die-stack { width: 560px; height: 280px; }\n  .feature-rolligan .meta-card .top .die.size-lg { width: 220px; height: 220px; padding: 24px; }\n  .feature-rolligan .meta-card .top .die.size-md { width: 160px; height: 160px; padding: 20px; }\n  .feature-rolligan .meta-card .top .die.size-md .pip { width: 18px; height: 18px; }\n  .feature-rolligan .meta-card .top .die.size-lg .pip { width: 22px; height: 22px; }\n  .feature-rolligan .specs {\n    display: grid; grid-template-columns: repeat(4, 1fr);\n    border-top: 1px solid var(--line);\n  }\n  .feature-rolligan .specs .item {\n    padding: 28px 24px; text-align: left;\n    border-right: 1px solid var(--line);\n  }\n  .feature-rolligan .specs .item:last-child { border-right: 0; }\n  .feature-rolligan .specs .k { font-size: 12px; letter-spacing: 0.04em; color: var(--mute); margin-bottom: 8px; font-weight: 500; text-transform: uppercase; }\n  .feature-rolligan .specs .v { font-size: 22px; font-weight: 600; letter-spacing: -0.015em; color: var(--ink); }\n  .feature-rolligan .meta-card .footer {\n    padding: 28px 40px; display: flex; align-items: center; justify-content: space-between;\n    border-top: 1px solid var(--line); background: var(--bg-3);\n  }\n  .feature-rolligan .meta-card .footer .label { font-size: 14px; color: var(--mute); }\n  .feature-rolligan .meta-card .footer .label strong { color: var(--ink); font-weight: 600; }\n  .feature-rolligan .title-block { text-align: center; margin-bottom: 40px; }\n  .feature-rolligan .title-block h2 {\n    font-size: clamp(60px, 8vw, 120px);\n    font-weight: 800; letter-spacing: -0.045em;\n  }\n  .feature-rolligan .title-block h2 .stop { color: var(--accent); }\n  .feature-rolligan .title-block .tag {\n    font-size: clamp(22px, 2vw, 30px); font-weight: 500; color: var(--ink-3); margin-top: 14px; letter-spacing: -0.018em;\n  }\n  .feature-rolligan .ctas { display: flex; justify-content: center; gap: 12px; margin-top: 28px; }\n\n  /* \u2500\u2500\u2500 STUDIO THESIS (dark) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n  .thesis {\n    background: var(--dark); color: var(--on-dark);\n    padding: 140px 0;\n    position: relative; overflow: hidden;\n  }\n  .thesis::before {\n    content: ''; position: absolute; left: 50%; top: -200px; width: 1200px; height: 600px;\n    transform: translateX(-50%);\n    background: radial-gradient(50% 50% at 50% 50%, color-mix(in srgb, var(--accent) 25%, transparent) 0%, transparent 70%);\n    pointer-events: none;\n  }\n  .thesis .container { position: relative; z-index: 1; }\n  .thesis .grid { display: grid; grid-template-columns: 5fr 7fr; gap: 80px; align-items: center; }\n  .thesis .eyebrow { color: var(--accent-2); }\n  .thesis .eyebrow .dot { background: var(--accent-2); box-shadow: 0 0 0 4px color-mix(in srgb, var(--accent) 25%, transparent); }\n  .thesis h2 { color: var(--on-dark); }\n  .thesis h2 .stop { color: var(--accent-2); }\n  .thesis .body { color: var(--on-dark-mute); max-width: 60ch; font-size: 18px; line-height: 1.6; }\n  .thesis .stats {\n    margin-top: 56px;\n    display: grid; grid-template-columns: repeat(4, 1fr);\n    gap: 0;\n    border-top: 1px solid var(--dark-line);\n  }\n  .thesis .stats .item { padding: 28px 0; border-right: 1px solid var(--dark-line); }\n  .thesis .stats .item:last-child { border-right: 0; }\n  .thesis .stats .item:first-child { padding-left: 0; }\n  .thesis .stats .item .v {\n    font-size: 56px; font-weight: 800; letter-spacing: -0.04em; color: #fff;\n    font-variant-numeric: tabular-nums; margin-bottom: 6px; line-height: 1;\n  }\n  .thesis .stats .item .k { font-size: 12px; color: var(--on-dark-mute); text-transform: uppercase; letter-spacing: 0.04em; font-weight: 500; }\n  .thesis .signature {\n    margin-top: 48px;\n    font-size: 16px; color: var(--on-dark-mute); font-weight: 500;\n  }\n  .thesis .signature strong { color: #fff; font-weight: 600; }\n\n  /* \u2500\u2500\u2500 CATALOG \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n  .catalog .shelf { margin-bottom: 80px; }\n  .catalog .shelf:last-child { margin-bottom: 0; }\n  .catalog .shelf-head {\n    display: flex; justify-content: space-between; align-items: baseline;\n    margin-bottom: 28px;\n  }\n  .catalog .shelf-head .title { display: flex; align-items: baseline; gap: 16px; }\n  .catalog .shelf-head h3 { font-size: 36px; font-weight: 700; letter-spacing: -0.025em; }\n  .catalog .shelf-head h3 .stop { color: var(--accent); }\n  .catalog .shelf-head .count { font-size: 14px; color: var(--mute); font-weight: 500; }\n  .catalog .shelf-head .arrow { color: var(--accent); font-size: 14px; font-weight: 500; }\n\n  .product-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 24px; }\n  .product-card {\n    background: var(--bg);\n    border: 1px solid var(--line);\n    border-radius: 28px;\n    padding: 40px;\n    min-height: 460px;\n    display: grid; grid-template-rows: auto 1fr auto;\n    gap: 24px;\n    position: relative; overflow: hidden;\n    transition: transform .4s cubic-bezier(.2,.7,.2,1), box-shadow .4s ease, border-color .4s ease;\n  }\n  .product-card:hover { transform: translateY(-4px); box-shadow: 0 30px 60px -20px rgba(20,22,40,0.18); border-color: var(--line-2); }\n  .product-card .head { display: flex; justify-content: space-between; align-items: center; }\n  .product-card .status {\n    display: inline-flex; align-items: center; gap: 8px;\n    font-size: 12.5px; color: var(--ink-3); font-weight: 500;\n  }\n  .product-card .status .dot { width: 7px; height: 7px; border-radius: 50%; }\n  .product-card .status.live .dot { background: #34c759; box-shadow: 0 0 0 4px color-mix(in srgb, #34c759 25%, transparent); }\n  .product-card .status.prog .dot { background: var(--accent); box-shadow: 0 0 0 4px color-mix(in srgb, var(--accent) 25%, transparent); }\n  .product-card .status.plan .dot { background: var(--mute); }\n  .product-card .meta-num { font-size: 12px; color: var(--mute); font-weight: 500; font-family: 'Geist Mono', monospace; }\n  .product-card .title-block h4 {\n    font-size: 36px; font-weight: 700; letter-spacing: -0.028em; line-height: 1; color: var(--ink);\n  }\n  .product-card .title-block h4 .stop { color: var(--accent); }\n  .product-card .title-block .desc { font-size: 16px; color: var(--ink-3); line-height: 1.5; margin-top: 10px; max-width: 38ch; }\n  .product-card .visual {\n    align-self: end; justify-self: center;\n    position: relative; width: 100%; max-width: 380px; height: 200px;\n    display: flex; align-items: flex-end; justify-content: center;\n  }\n  .product-card .foot {\n    display: flex; justify-content: space-between; align-items: center;\n    padding-top: 20px; border-top: 1px solid var(--line);\n    font-size: 13.5px; color: var(--mute); font-weight: 500;\n  }\n  .product-card .foot .arrow { color: var(--accent); font-size: 16px; transition: transform .25s ease; }\n  .product-card:hover .foot .arrow { transform: translateX(4px); }\n\n  /* Rolligan mini visual */\n  .vis-dice { display: flex; gap: 12px; align-items: flex-end; }\n  .vis-dice .die-mini { width: 80px; height: 80px; padding: 11px; border-radius: 16px; }\n  .vis-dice .die-mini .pip { width: 11px; height: 11px; }\n  .vis-dice .die-mini.lift { transform: translateY(-14px) rotate(-6deg); }\n  .vis-dice .die-mini.tilt { transform: rotate(8deg); }\n\n  /* YulePick visual */\n  .vis-yulepick {\n    width: 320px; height: 200px;\n    background: linear-gradient(180deg, #fafafb 0%, #f0f0f3 100%);\n    border-radius: 16px;\n    position: relative; padding: 16px;\n    display: flex; flex-direction: column; gap: 8px;\n    border: 1px solid var(--line);\n  }\n  .vis-yulepick .h {\n    font-size: 10px; color: var(--mute); text-transform: uppercase; letter-spacing: 0.06em; font-weight: 600;\n  }\n  .vis-yulepick .gift {\n    background: #fff; border-radius: 10px; padding: 10px 12px; font-size: 12.5px; color: var(--ink);\n    border: 1px solid var(--line);\n    display: flex; align-items: center; gap: 10px;\n    box-shadow: 0 2px 6px -2px rgba(20,22,40,0.06);\n  }\n  .vis-yulepick .gift .av {\n    width: 24px; height: 24px; border-radius: 50%; background: var(--accent); color: #fff;\n    display: flex; align-items: center; justify-content: center; font-size: 11px; font-weight: 700;\n    flex-shrink: 0;\n  }\n  .vis-yulepick .gift.you { background: var(--accent-soft); border-color: color-mix(in srgb, var(--accent) 25%, transparent); }\n  .vis-yulepick .gift.you .av { background: var(--ink); }\n  .vis-yulepick .bow {\n    position: absolute; top: -10px; right: 22px;\n    width: 22px; height: 22px; background: var(--accent); border-radius: 4px;\n    transform: rotate(45deg);\n    box-shadow: 0 6px 16px -4px color-mix(in srgb, var(--accent) 40%, transparent);\n  }\n\n  .future-card {\n    border: 1.5px dashed var(--line-2);\n    border-radius: 28px;\n    padding: 56px;\n    text-align: center;\n    background: linear-gradient(180deg, transparent, color-mix(in srgb, var(--accent) 4%, transparent));\n  }\n  .future-card h4 { font-size: 24px; font-weight: 600; letter-spacing: -0.02em; margin-bottom: 10px; }\n  .future-card p { font-size: 16px; color: var(--ink-3); max-width: 50ch; margin: 0 auto 18px; }\n\n  /* \u2500\u2500\u2500 PRIVACY \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n  .privacy h2 .stop { color: var(--accent); }\n  .universal-grid {\n    display: grid; grid-template-columns: repeat(3, 1fr); gap: 24px;\n    margin-bottom: 56px;\n  }\n  .universal-card {\n    background: var(--bg); border: 1px solid var(--line); border-radius: 22px;\n    padding: 32px;\n  }\n  .universal-card .ic {\n    width: 44px; height: 44px; border-radius: 12px;\n    background: var(--accent-soft);\n    color: var(--accent);\n    display: flex; align-items: center; justify-content: center; margin-bottom: 18px;\n    border: 1px solid color-mix(in srgb, var(--accent) 20%, transparent);\n  }\n  .universal-card h4 { font-size: 19px; font-weight: 600; margin-bottom: 8px; letter-spacing: -0.015em; }\n  .universal-card p { font-size: 14.5px; color: var(--ink-3); line-height: 1.55; }\n\n  .per-app {\n    background: var(--bg);\n    border: 1px solid var(--line);\n    border-radius: 22px;\n    overflow: hidden;\n  }\n  .per-app .head {\n    padding: 24px 32px;\n    background: var(--bg-2);\n    border-bottom: 1px solid var(--line);\n    display: flex; justify-content: space-between; align-items: center;\n  }\n  .per-app .head .label { font-size: 13px; font-weight: 600; color: var(--ink); text-transform: uppercase; letter-spacing: 0.04em; }\n  .per-app .head .meta { font-size: 13px; color: var(--mute); }\n  .per-app .row {\n    display: grid; grid-template-columns: 220px 1fr 200px;\n    padding: 24px 32px; border-bottom: 1px solid var(--line);\n    align-items: center; gap: 32px;\n  }\n  .per-app .row:last-child { border-bottom: 0; }\n  .per-app .row .app { font-size: 19px; font-weight: 600; letter-spacing: -0.018em; }\n  .per-app .row .app .stop { color: var(--accent); }\n  .per-app .row .note { font-size: 14.5px; color: var(--ink-3); line-height: 1.5; }\n  .per-app .row .note strong { color: var(--ink); font-weight: 600; }\n  .per-app .row .pill {\n    display: inline-flex; align-items: center; gap: 6px;\n    padding: 6px 12px; border-radius: 999px;\n    font-size: 12px; font-weight: 500;\n    background: var(--bg-2); color: var(--ink-3);\n    border: 1px solid var(--line);\n    justify-self: end;\n  }\n  .per-app .row .pill .dot { width: 6px; height: 6px; border-radius: 50%; }\n  .per-app .row .pill.on .dot { background: #34c759; }\n  .per-app .row .pill.sync .dot { background: var(--accent); }\n  .per-app .row .pill.hybrid .dot { background: #ff9500; }\n\n  /* \u2500\u2500\u2500 NEWSROOM \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n  .newsroom .list { border-top: 1px solid var(--line); }\n  .news-row {\n    display: grid; grid-template-columns: 140px 1fr 200px;\n    gap: 32px; padding: 28px 0; border-bottom: 1px solid var(--line);\n    align-items: baseline; transition: padding .25s ease;\n  }\n  .news-row:hover { padding-left: 8px; }\n  .news-row .date { font-size: 13px; color: var(--mute); font-family: 'Geist Mono', monospace; letter-spacing: 0.02em; }\n  .news-row .title { font-size: 22px; font-weight: 600; letter-spacing: -0.018em; color: var(--ink); line-height: 1.25; }\n  .news-row .title .stop { color: var(--accent); }\n  .news-row .tag { font-size: 13px; color: var(--accent); font-weight: 500; text-align: right; }\n\n  /* \u2500\u2500\u2500 CTA BAND \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n  .cta-band {\n    margin: 0 auto; max-width: 1240px;\n    padding: 0 32px;\n  }\n  .cta-band .card {\n    background: linear-gradient(135deg, var(--dark) 0%, var(--dark-2) 100%);\n    color: #fff;\n    border-radius: 32px;\n    padding: 80px 64px;\n    position: relative; overflow: hidden;\n    display: grid; grid-template-columns: 7fr 5fr; gap: 56px; align-items: center;\n  }\n  .cta-band .card::before {\n    content: ''; position: absolute; right: -100px; top: -100px;\n    width: 500px; height: 500px;\n    background: radial-gradient(50% 50% at 50% 50%, color-mix(in srgb, var(--accent) 35%, transparent) 0%, transparent 70%);\n    pointer-events: none;\n  }\n  .cta-band h2 { color: #fff; max-width: 14ch; position: relative; }\n  .cta-band h2 .stop { color: var(--accent-2); }\n  .cta-band p { color: var(--on-dark-mute); font-size: 18px; margin: 16px 0 0; max-width: 40ch; position: relative; }\n  .cta-band form { display: flex; gap: 8px; position: relative; }\n  .cta-band input {\n    flex: 1; background: rgba(255,255,255,0.08); color: #fff;\n    border: 1px solid rgba(255,255,255,0.15); padding: 14px 18px;\n    border-radius: 999px; font-size: 15px; font-family: inherit;\n    outline: none; transition: border-color .25s ease;\n  }\n  .cta-band input::placeholder { color: rgba(255,255,255,0.4); }\n  .cta-band input:focus { border-color: var(--accent); }\n  .cta-band .btn-fill { box-shadow: 0 8px 24px -6px var(--accent); }\n  .cta-band .small { font-size: 12.5px; color: var(--on-dark-mute); margin-top: 12px; position: relative; }\n\n  /* \u2500\u2500\u2500 FOOTER \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n  footer {\n    background: var(--bg-2);\n    border-top: 1px solid var(--line);\n    padding: 80px 0 32px;\n  }\n  footer .container { max-width: 1240px; }\n  footer .dir {\n    display: grid; grid-template-columns: 2fr 1fr 1fr 1fr 1fr; gap: 48px;\n    padding-bottom: 56px;\n    border-bottom: 1px solid var(--line);\n  }\n  footer .dir .left p { font-size: 14px; color: var(--mute); margin-top: 14px; max-width: 32ch; line-height: 1.55; }\n  footer .dir h5 { font-size: 12.5px; font-weight: 600; color: var(--ink); text-transform: uppercase; letter-spacing: 0.04em; margin-bottom: 14px; }\n  footer .dir ul { list-style: none; padding: 0; margin: 0; display: flex; flex-direction: column; gap: 8px; }\n  footer .dir a { font-size: 14px; color: var(--ink-3); }\n  footer .dir a:hover { color: var(--ink); }\n  footer .colophon {\n    display: flex; justify-content: space-between; align-items: center;\n    padding-top: 24px;\n    font-size: 12.5px; color: var(--mute);\n  }\n  footer .colophon .links { display: flex; gap: 18px; }\n\n  /* \u2500\u2500\u2500 REVEAL \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n  .reveal { opacity: 0; transform: translateY(20px); transition: opacity .9s cubic-bezier(.2,.7,.2,1), transform .9s cubic-bezier(.2,.7,.2,1); }\n  .reveal.in { opacity: 1; transform: none; }\n  .reveal.d1 { transition-delay: .08s; }\n  .reveal.d2 { transition-delay: .16s; }\n  .reveal.d3 { transition-delay: .24s; }\n  @media (prefers-reduced-motion: reduce) {\n    .reveal { opacity: 1; transform: none; transition: none; }\n    .die, .die.pos-a, .die.pos-b, .die.pos-c, .die.pos-d, .die.pos-e { animation: none; }\n    .hero .badge .dot::after { animation: none; }\n  }\n\n  /* \u2500\u2500\u2500 TWEAKS PANEL \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n  .tweaks {\n    position: fixed; right: 16px; bottom: 16px; z-index: 100;\n    background: rgba(255,255,255,0.96);\n    backdrop-filter: blur(20px);\n    border: 1px solid var(--line);\n    border-radius: 16px;\n    padding: 18px; min-width: 260px;\n    box-shadow: 0 24px 48px -16px rgba(20,22,40,0.18);\n    font-size: 14px;\n    display: none;\n  }\n  .tweaks.open { display: block; }\n  .tweaks .head { display: flex; justify-content: space-between; align-items: center; margin-bottom: 14px; }\n  .tweaks .head h6 { font-size: 13px; font-weight: 600; text-transform: uppercase; letter-spacing: 0.04em; color: var(--ink); margin: 0; }\n  .tweaks .head button {\n    border: none; background: none; cursor: pointer; color: var(--mute); font-size: 18px;\n    padding: 2px 6px; border-radius: 4px;\n  }\n  .tweaks .head button:hover { background: var(--bg-2); color: var(--ink); }\n  .tweaks .label { font-size: 11px; color: var(--mute); text-transform: uppercase; letter-spacing: 0.06em; font-weight: 600; margin-bottom: 8px; }\n  .tweaks .swatches { display: flex; gap: 8px; flex-wrap: wrap; }\n  .tweaks .swatch {\n    width: 36px; height: 36px; border-radius: 10px; cursor: pointer;\n    border: 2px solid transparent;\n    transition: transform .15s ease, border-color .15s ease;\n    position: relative;\n  }\n  .tweaks .swatch:hover { transform: scale(1.05); }\n  .tweaks .swatch.active { border-color: var(--ink); }\n  .tweaks .swatch.active::after {\n    content: '\u2713'; position: absolute; inset: 0; display: flex; align-items: center; justify-content: center;\n    color: #fff; font-weight: 700; font-size: 14px;\n    text-shadow: 0 1px 2px rgba(0,0,0,0.3);\n  }\n  .tweaks .name { font-size: 12px; color: var(--mute); margin-top: 10px; }\n  .tweaks .name strong { color: var(--ink); font-weight: 600; }\n\n/* page-specific */\n\n  /* \u2500\u2500\u2500 DICE (from homepage) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n  .stage { margin: 56px auto 0; position: relative; width: 100%; max-width: 980px; height: 460px; display: flex; align-items: flex-end; justify-content: center; }\n  .die-stack { position: relative; width: 720px; height: 360px; }\n  .die {\n    position: absolute; border-radius: 32px;\n    background: linear-gradient(160deg, #ffffff 0%, #fafafb 50%, #ececf0 100%);\n    box-shadow: 0 2px 0 rgba(255,255,255,1) inset, 0 -2px 0 rgba(0,0,0,0.04) inset, 0 24px 32px -8px rgba(20,22,40,0.12), 0 60px 80px -20px rgba(20,22,40,0.22);\n    padding: 28px; display: grid; grid-template-columns: repeat(3, 1fr); grid-template-rows: repeat(3, 1fr);\n    border: 1px solid rgba(255,255,255,0.6);\n  }\n  .die .pip {\n    width: 24px; height: 24px; align-self: center; justify-self: center; border-radius: 50%;\n    background: radial-gradient(circle at 35% 30%, color-mix(in srgb, var(--accent) 90%, #000 0%) 0%, color-mix(in srgb, var(--accent) 60%, #000 35%) 80%);\n    box-shadow: inset 0 1px 1px rgba(255,255,255,0.4), inset 0 -1px 2px rgba(0,0,0,0.25);\n  }\n  .die.ink { background: linear-gradient(160deg, #2a2a30 0%, #1c1c22 50%, #0b0b10 100%); border: 1px solid rgba(255,255,255,0.06); }\n  .die.ink .pip { background: radial-gradient(circle at 35% 30%, #fff 0%, #d2d2d7 80%); }\n  .die.accent {\n    background: linear-gradient(160deg, color-mix(in srgb, var(--accent) 70%, #fff) 0%, var(--accent) 60%, color-mix(in srgb, var(--accent) 70%, #000) 100%);\n    border: 1px solid color-mix(in srgb, var(--accent) 50%, #fff);\n    box-shadow: 0 2px 0 rgba(255,255,255,0.3) inset, 0 24px 40px -8px color-mix(in srgb, var(--accent) 35%, transparent), 0 60px 80px -20px color-mix(in srgb, var(--accent) 35%, transparent);\n  }\n  .die.accent .pip { background: radial-gradient(circle at 35% 30%, #ffffff 0%, color-mix(in srgb, var(--accent) 10%, #fff) 80%); }\n  .die.f5 .pip:nth-child(1){grid-area:1/1}.die.f5 .pip:nth-child(2){grid-area:1/3}.die.f5 .pip:nth-child(3){grid-area:2/2}.die.f5 .pip:nth-child(4){grid-area:3/1}.die.f5 .pip:nth-child(5){grid-area:3/3}\n  .die.f3 .pip:nth-child(1){grid-area:1/1}.die.f3 .pip:nth-child(2){grid-area:2/2}.die.f3 .pip:nth-child(3){grid-area:3/3}\n  .die.f6 .pip:nth-child(1){grid-area:1/1}.die.f6 .pip:nth-child(2){grid-area:1/3}.die.f6 .pip:nth-child(3){grid-area:2/1}.die.f6 .pip:nth-child(4){grid-area:2/3}.die.f6 .pip:nth-child(5){grid-area:3/1}.die.f6 .pip:nth-child(6){grid-area:3/3}\n  .die.f2 .pip:nth-child(1){grid-area:1/1}.die.f2 .pip:nth-child(2){grid-area:3/3}\n  .die.f4 .pip:nth-child(1){grid-area:1/1}.die.f4 .pip:nth-child(2){grid-area:1/3}.die.f4 .pip:nth-child(3){grid-area:3/1}.die.f4 .pip:nth-child(4){grid-area:3/3}\n  .die.size-lg { width: 280px; height: 280px; }\n  .die.size-md { width: 200px; height: 200px; padding: 24px; }\n  .die.size-md .pip { width: 20px; height: 20px; }\n  .die.size-sm { width: 150px; height: 150px; padding: 20px; }\n  .die.size-sm .pip { width: 16px; height: 16px; }\n  .die.pos-a { left: 50%; bottom: 30px; transform: translateX(-50%); animation: float-a 6s ease-in-out infinite; }\n  .die.pos-b { left: 12%; bottom: 60px; transform: rotate(-12deg); animation: float-b 7s ease-in-out infinite .4s; }\n  .die.pos-c { right: 12%; bottom: 70px; transform: rotate(11deg); animation: float-c 7.5s ease-in-out infinite .8s; }\n  .die.pos-d { left: 28%; bottom: 0; transform: rotate(-5deg); animation: float-d 8s ease-in-out infinite .2s; opacity: 0.85; }\n  .die.pos-e { right: 28%; bottom: 5px; transform: rotate(7deg); animation: float-e 8s ease-in-out infinite .6s; opacity: 0.85; }\n  @keyframes float-a { 0%,100% { transform: translateX(-50%) translateY(0) rotate(0); } 50% { transform: translateX(-50%) translateY(-14px) rotate(2deg); } }\n  @keyframes float-b { 0%,100% { transform: rotate(-12deg) translateY(0); } 50% { transform: rotate(-14deg) translateY(-10px); } }\n  @keyframes float-c { 0%,100% { transform: rotate(11deg) translateY(0); } 50% { transform: rotate(13deg) translateY(-10px); } }\n  @keyframes float-d { 0%,100% { transform: rotate(-5deg) translateY(0); } 50% { transform: rotate(-7deg) translateY(-6px); } }\n  @keyframes float-e { 0%,100% { transform: rotate(7deg) translateY(0); } 50% { transform: rotate(9deg) translateY(-7px); } }\n  @media (prefers-reduced-motion: reduce) { .die.pos-a, .die.pos-b, .die.pos-c, .die.pos-d, .die.pos-e { animation: none; } }\n  .stage-shadow { position: absolute; left: 50%; bottom: 4px; transform: translateX(-50%); width: 580px; height: 24px; background: radial-gradient(ellipse, rgba(20,22,40,0.22) 0%, transparent 70%); filter: blur(6px); }\n  .stage-floor { position: absolute; left: 0; right: 0; bottom: 0; height: 1px; background: linear-gradient(90deg, transparent, var(--line), transparent); }\n\n  /* Hero glow + specs row */\n  .hero-rolligan { position: relative; padding: 64px 0 32px; overflow: hidden; }\n  .hero-rolligan::before { content: ''; position: absolute; left: 50%; top: -100px; width: 1000px; height: 600px; transform: translateX(-50%); background: radial-gradient(50% 50% at 50% 50%, color-mix(in srgb, var(--accent) 16%, transparent) 0%, transparent 65%); pointer-events: none; }\n  .hero-rolligan .container { position: relative; text-align: center; }\n  .badge { display: inline-flex; align-items: center; gap: 8px; padding: 6px 14px; border-radius: 999px; background: color-mix(in srgb, #34c759 12%, transparent); color: #1f9d3e; border: 1px solid color-mix(in srgb, #34c759 30%, transparent); font-size: 13.5px; font-weight: 500; margin-bottom: 28px; }\n  .badge .dot { width: 7px; height: 7px; border-radius: 50%; background: #34c759; box-shadow: 0 0 0 4px color-mix(in srgb, #34c759 25%, transparent); }\n  .hero-rolligan h1 { max-width: 14ch; margin: 0 auto; color: var(--ink); }\n\n  .specs-strip {\n    display: grid; grid-template-columns: repeat(4, 1fr);\n    background: var(--bg); border: 1px solid var(--line); border-radius: 22px; overflow: hidden;\n    margin-top: 32px;\n  }\n  .specs-strip .item { padding: 22px 24px; text-align: left; border-right: 1px solid var(--line); }\n  .specs-strip .item:last-child { border-right: 0; }\n  .specs-strip .k { font-size: 11.5px; color: var(--mute); text-transform: uppercase; letter-spacing: 0.06em; font-weight: 600; margin-bottom: 6px; }\n  .specs-strip .v { font-size: 22px; font-weight: 600; letter-spacing: -0.018em; color: var(--ink); }\n\n  /* Rules grid */\n  .rules { display: grid; grid-template-columns: repeat(4, 1fr); gap: 16px; }\n  .rule-card { background: var(--bg); border: 1px solid var(--line); border-radius: 22px; padding: 28px; min-height: 220px; display: flex; flex-direction: column; gap: 10px; }\n  .rule-card .num { font-family: 'Geist Mono', monospace; font-size: 12px; letter-spacing: 0.08em; color: var(--accent); margin-bottom: 8px; }\n  .rule-card h4 { font-size: 22px; }\n  .rule-card p { font-size: 14.5px; color: var(--ink-3); line-height: 1.55; }\n\n  /* Phone mock */\n  .device-row { display: grid; grid-template-columns: 5fr 7fr; gap: 64px; align-items: center; }\n  .phone-shell {\n    width: 280px; aspect-ratio: 9/19; background: var(--ink); border-radius: 44px; padding: 10px;\n    box-shadow: 0 30px 60px -16px rgba(20,22,40,0.32);\n    margin: 0 auto;\n  }\n  .phone-screen {\n    width: 100%; height: 100%; background: var(--bg);\n    border-radius: 36px; padding: 36px 16px 16px; display: flex; flex-direction: column;\n  }\n  .phone-bar { display: flex; justify-content: space-between; font-size: 11px; color: var(--mute); margin-bottom: 10px; }\n  .phone-header { text-align: center; padding: 8px 0 14px; border-bottom: 1px solid var(--line); margin-bottom: 14px; }\n  .phone-header h5 { font-size: 16px; }\n  .phone-score { display: flex; justify-content: space-between; padding: 10px 14px; background: var(--bg-2); border-radius: 12px; margin-bottom: 16px; font-size: 13px; }\n  .phone-score b { font-weight: 600; color: var(--ink); }\n  .phone-dice { display: grid; grid-template-columns: repeat(3, 1fr); gap: 8px; margin-bottom: 16px; }\n  .phone-dice .face {\n    aspect-ratio: 1; border-radius: 10px;\n    background: var(--bg-2); border: 1px solid var(--line);\n    display: grid; place-items: center; font-size: 28px; font-weight: 700; color: var(--ink);\n  }\n  .phone-dice .face.hot { background: var(--accent); color: #fff; border-color: var(--accent); box-shadow: 0 6px 16px -4px color-mix(in srgb, var(--accent) 40%, transparent); }\n  .phone-turn { text-align: center; padding: 14px; background: var(--bg-2); border-radius: 12px; margin-bottom: 14px; }\n  .phone-turn .k { font-size: 10px; text-transform: uppercase; letter-spacing: 0.06em; color: var(--mute); font-weight: 600; }\n  .phone-turn .v { font-size: 32px; font-weight: 700; color: var(--ink); margin-top: 2px; letter-spacing: -0.02em; }\n  .phone-btns { margin-top: auto; display: flex; flex-direction: column; gap: 6px; }\n  .phone-btn { padding: 12px; border-radius: 12px; font-size: 13px; font-weight: 500; text-align: center; }\n  .phone-btn.primary { background: var(--ink); color: #fff; }\n  .phone-btn.ghost { background: var(--bg-2); color: var(--ink); }\n\n  /* FAQ */\n  .faq-list { background: var(--bg); border: 1px solid var(--line); border-radius: 22px; overflow: hidden; }\n  .faq { padding: 22px 28px; border-bottom: 1px solid var(--line); }\n  .faq:last-child { border-bottom: 0; }\n  .faq summary { display: flex; justify-content: space-between; align-items: center; cursor: pointer; list-style: none; font-size: 17px; font-weight: 500; letter-spacing: -0.012em; }\n  .faq summary::-webkit-details-marker { display: none; }\n  .faq[open] summary { color: var(--accent); }\n  .faq p { font-size: 15px; color: var(--ink-3); line-height: 1.6; margin-top: 12px; max-width: 64ch; }\n  .faq .ch { color: var(--mute); transition: transform .2s ease; }\n  .faq[open] .ch { transform: rotate(45deg); color: var(--accent); }\n\n/* static-port overrides */\n.reveal{opacity:1 !important;transform:none !important;transition:none !important}\n.tweaks{display:none !important}\n"

const BODY = "\n\n<div class=\"topbar\">\n  <strong>Rolligan is live on the App Store.</strong> Free with a $2.99 unlock for variant rules and theming. <a href=\"#download\">Get it \u2192</a>\n</div>\n\n<nav class=\"primary\">\n  <div class=\"container\">\n    <a href=\"/\" class=\"wordmark\"><span>Clarendon</span><span class=\"dot\"></span></a>\n    <div class=\"links\">\n      <a href=\"/#catalog\" class=\"active\">Catalog</a>\n      <a href=\"/studio\">Studio</a>\n      <a href=\"/privacy\">Privacy</a>\n      <a href=\"/#newsroom\">Newsroom</a>\n      <a href=\"mailto:hello@clarendon.dev\">Contact</a>\n    </div>\n    <div class=\"nav-cta\">\n      <a href=\"/support\" class=\"sign\">Support</a>\n      <a href=\"mailto:hello@clarendon.dev\" class=\"btn btn-fill btn-sm\">Get in touch</a>\n    </div>\n  </div>\n</nav>\n\n<!-- HERO -->\n<section class=\"hero-rolligan\">\n  <div class=\"container\">\n    <p class=\"crumbs reveal\" style=\"font-size: 13px; color: var(--mute); margin-bottom: 20px;\"><a href=\"/\" style=\"color: var(--accent);\">Clarendon.</a>  /  <a href=\"/#catalog\" style=\"color: var(--accent);\">Catalog</a>  /  Games  /  Rolligan</p>\n    <div class=\"badge reveal\"><span class=\"dot\"></span> Available now on the App Store</div>\n    <h1 class=\"reveal d1\">Rolligan<span class=\"stop\">.</span></h1>\n    <p class=\"sub reveal d2\" style=\"margin: 22px auto 32px; max-width: 640px; font-size: 22px; line-height: 1.45; color: var(--ink-3); font-weight: 400;\">Push your luck. Or don&apos;t. The dice party game built for the actual living room \u2014 pass-and-play, two to eight at the table, fifteen minutes to learn.</p>\n    <div class=\"reveal d3\" style=\"display: flex; gap: 12px; justify-content: center;\">\n      <a href=\"https://rolligan.com\" class=\"btn btn-fill\">Visit rolligan.com \u2192</a>\n      <a href=\"#how\" class=\"btn btn-ghost\">How it plays</a>\n    </div>\n\n    <!-- Dice scene -->\n    <div class=\"stage reveal d3\" aria-hidden=\"true\">\n      <div class=\"die-stack\">\n        <div class=\"die accent size-lg pos-a f5\"><span class=\"pip\"></span><span class=\"pip\"></span><span class=\"pip\"></span><span class=\"pip\"></span><span class=\"pip\"></span></div>\n        <div class=\"die size-md pos-b f3\"><span class=\"pip\"></span><span class=\"pip\"></span><span class=\"pip\"></span></div>\n        <div class=\"die ink size-md pos-c f6\"><span class=\"pip\"></span><span class=\"pip\"></span><span class=\"pip\"></span><span class=\"pip\"></span><span class=\"pip\"></span><span class=\"pip\"></span></div>\n        <div class=\"die size-sm pos-d f2\"><span class=\"pip\"></span><span class=\"pip\"></span></div>\n        <div class=\"die size-sm pos-e f4\"><span class=\"pip\"></span><span class=\"pip\"></span><span class=\"pip\"></span><span class=\"pip\"></span></div>\n      </div>\n      <div class=\"stage-shadow\"></div>\n      <div class=\"stage-floor\"></div>\n    </div>\n  </div>\n</section>\n\n<!-- SPECS STRIP -->\n<section style=\"padding: 32px 0 88px;\">\n  <div class=\"container\">\n    <div class=\"specs-strip reveal\">\n      <div class=\"item\"><div class=\"k\">Players</div><div class=\"v\">2 \u2013 8</div></div>\n      <div class=\"item\"><div class=\"k\">Format</div><div class=\"v\">iPhone \u00b7 iPad</div></div>\n      <div class=\"item\"><div class=\"k\">Price</div><div class=\"v\">Free \u00b7 $2.99 unlock</div></div>\n      <div class=\"item\"><div class=\"k\">Status</div><div class=\"v\" style=\"color: var(--accent);\">Available now</div></div>\n    </div>\n  </div>\n</section>\n\n<!-- RULES OF PLAY -->\n<section id=\"how\" class=\"alt\">\n  <div class=\"container\">\n    <div class=\"section-head reveal\">\n      <div class=\"eyebrow\"><span class=\"dot\"></span> Rules of play</div>\n      <h2 style=\"margin-top: 14px;\">Teach it in thirty seconds<span class=\"stop\">.</span></h2>\n      <p class=\"sub\">Four steps, one decision per roll: cash in, or keep rolling and risk losing it all.</p>\n    </div>\n    <div class=\"rules\">\n      <div class=\"rule-card reveal\">\n        <div class=\"num\">01</div>\n        <h4>Roll<span class=\"stop\">.</span></h4>\n        <p>Your turn. Roll all six dice. Score the points. Set aside any scoring dice.</p>\n      </div>\n      <div class=\"rule-card reveal d1\">\n        <div class=\"num\">02</div>\n        <h4>Decide<span class=\"stop\">.</span></h4>\n        <p>Bank what you&apos;ve earned and end your turn safely \u2014 or roll the remaining dice and push for more.</p>\n      </div>\n      <div class=\"rule-card reveal d2\">\n        <div class=\"num\">03</div>\n        <h4>Bust<span class=\"stop\">.</span></h4>\n        <p>Roll a turn with no scoring dice and you lose every unbanked point this turn. The cost of greed.</p>\n      </div>\n      <div class=\"rule-card reveal d3\">\n        <div class=\"num\">04</div>\n        <h4>Win<span class=\"stop\">.</span></h4>\n        <p>First player to ten thousand wins. Then immediately rematch, because you&apos;re not done.</p>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- IN HAND (device) -->\n<section>\n  <div class=\"container\">\n    <div class=\"device-row\">\n      <div class=\"reveal\">\n        <div class=\"phone-shell\">\n          <div class=\"phone-screen\">\n            <div class=\"phone-bar\"><span>9:41</span><span>\u25cf\u25cf\u25cf</span></div>\n            <div class=\"phone-header\">\n              <h5>Rolligan</h5>\n            </div>\n            <div class=\"phone-score\">\n              <span><b>You</b> 4,250</span>\n              <span style=\"color: var(--mute);\">Lin 5,100</span>\n            </div>\n            <div class=\"phone-dice\">\n              <div class=\"face\">3</div>\n              <div class=\"face\">5</div>\n              <div class=\"face hot\">1</div>\n              <div class=\"face\">6</div>\n              <div class=\"face\">2</div>\n              <div class=\"face\">5</div>\n            </div>\n            <div class=\"phone-turn\">\n              <div class=\"k\">This turn</div>\n              <div class=\"v\">+850</div>\n            </div>\n            <div class=\"phone-btns\">\n              <div class=\"phone-btn primary\">Bank it</div>\n              <div class=\"phone-btn ghost\">Roll again</div>\n            </div>\n          </div>\n        </div>\n      </div>\n      <div class=\"reveal d1\">\n        <div class=\"eyebrow\"><span class=\"dot\"></span> Built for the table</div>\n        <h2 style=\"margin-top: 14px;\">A single device<span class=\"stop\">.</span><br>Eight friends<span class=\"stop\">.</span></h2>\n        <p class=\"body\" style=\"margin-top: 22px; font-size: 18px;\">\n          Rolligan is pass-and-play by design. One phone (or one iPad) does the work \u2014 keeping score, managing turns, telling you when you busted with a sound effect you&apos;ll come to love. No accounts. No Wi-Fi. No second device required.\n        </p>\n        <ul style=\"list-style: none; padding: 0; margin: 28px 0 0; display: flex; flex-direction: column; gap: 12px;\">\n          <li style=\"display: flex; align-items: center; gap: 14px; font-size: 16px;\">\n            <span style=\"width: 20px; height: 20px; border-radius: 50%; background: var(--accent-soft); color: var(--accent); display: flex; align-items: center; justify-content: center; font-size: 12px; font-weight: 700;\">\u2713</span>\n            Native Swift \u00b7 120 fps on supported devices\n          </li>\n          <li style=\"display: flex; align-items: center; gap: 14px; font-size: 16px;\">\n            <span style=\"width: 20px; height: 20px; border-radius: 50%; background: var(--accent-soft); color: var(--accent); display: flex; align-items: center; justify-content: center; font-size: 12px; font-weight: 700;\">\u2713</span>\n            Haptic feedback \u00b7 sound effects designed for the room\n          </li>\n          <li style=\"display: flex; align-items: center; gap: 14px; font-size: 16px;\">\n            <span style=\"width: 20px; height: 20px; border-radius: 50%; background: var(--accent-soft); color: var(--accent); display: flex; align-items: center; justify-content: center; font-size: 12px; font-weight: 700;\">\u2713</span>\n            VoiceOver, Dynamic Type, and color-blind safe palettes\n          </li>\n          <li style=\"display: flex; align-items: center; gap: 14px; font-size: 16px;\">\n            <span style=\"width: 20px; height: 20px; border-radius: 50%; background: var(--accent-soft); color: var(--accent); display: flex; align-items: center; justify-content: center; font-size: 12px; font-weight: 700;\">\u2713</span>\n            No account \u00b7 no online required \u00b7 the dice are kept honest by physics\n          </li>\n        </ul>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- WHAT'S IN THE UNLOCK -->\n<section class=\"alt\">\n  <div class=\"container\">\n    <div class=\"section-head reveal\">\n      <div class=\"eyebrow\"><span class=\"dot\"></span> Pricing</div>\n      <h2 style=\"margin-top: 14px;\">Free to play<span class=\"stop\">.</span> Once for the rest<span class=\"stop\">.</span></h2>\n      <p class=\"sub\">Rolligan is free. The $2.99 unlock opens up variant rules, custom themes, and a deeper stats screen \u2014 buy it once and it&apos;s yours forever, on every device tied to your Apple ID.</p>\n    </div>\n    <div style=\"display: grid; grid-template-columns: 1fr 1fr; gap: 16px;\">\n      <div class=\"card reveal\">\n        <h3 style=\"font-size: 22px; margin-bottom: 8px;\">Rolligan<span class=\"stop\">.</span> Free</h3>\n        <div style=\"font-size: 36px; font-weight: 700; letter-spacing: -0.025em; margin: 6px 0 16px;\">$0</div>\n        <ul style=\"list-style: none; padding: 0; margin: 0; display: flex; flex-direction: column; gap: 10px; font-size: 14.5px; color: var(--ink-3);\">\n          <li>\u2713 Pass-and-play, 2 \u2013 8 players</li>\n          <li>\u2713 Standard rule set</li>\n          <li>\u2713 Default theme</li>\n          <li>\u2713 Per-game stats</li>\n          <li style=\"color: var(--mute);\">\u2014 Variant rules</li>\n          <li style=\"color: var(--mute);\">\u2014 Custom themes</li>\n        </ul>\n      </div>\n      <div class=\"card reveal d1\" style=\"background: linear-gradient(135deg, var(--accent) 0%, var(--accent-ink) 100%); color: #fff; border-color: var(--accent);\">\n        <div class=\"eyebrow\" style=\"color: #fff;\"><span class=\"dot\" style=\"background: #fff;\"></span> Recommended</div>\n        <h3 style=\"font-size: 22px; margin: 8px 0 8px;\">Rolligan<span style=\"color: #fff;\">.</span> Unlock</h3>\n        <div style=\"font-size: 36px; font-weight: 700; letter-spacing: -0.025em; margin: 6px 0 4px;\">$2.99</div>\n        <div style=\"font-size: 13px; color: rgba(255,255,255,0.7); margin-bottom: 16px;\">One-time purchase \u00b7 all devices</div>\n        <ul style=\"list-style: none; padding: 0; margin: 0; display: flex; flex-direction: column; gap: 10px; font-size: 14.5px; color: rgba(255,255,255,0.92);\">\n          <li>\u2713 Everything in Free</li>\n          <li>\u2713 Variant rule sets (Risk it, Stop short, Bank or bust)</li>\n          <li>\u2713 Five custom themes</li>\n          <li>\u2713 Lifetime stats &amp; head-to-head history</li>\n          <li>\u2713 Future content updates included</li>\n        </ul>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- FAQ -->\n<section>\n  <div class=\"container\">\n    <div class=\"section-head reveal\">\n      <div class=\"eyebrow\"><span class=\"dot\"></span> FAQ</div>\n      <h2 style=\"margin-top: 14px;\">Things people ask<span class=\"stop\">.</span></h2>\n    </div>\n    <div class=\"faq-list reveal\" style=\"max-width: 880px; margin: 0 auto;\">\n      <details class=\"faq\">\n        <summary>Does Rolligan work offline?<span class=\"ch\">+</span></summary>\n        <p>Yes. The entire game runs on-device with no network requirement. Play in a cabin, on a plane, in your basement \u2014 anywhere with one iPhone or iPad and at least one other person.</p>\n      </details>\n      <details class=\"faq\">\n        <summary>Is there an Android version?<span class=\"ch\">+</span></summary>\n        <p>Not currently. Clarendon is an iOS-only studio. We&apos;d rather make one platform feel native than make two feel half-built.</p>\n      </details>\n      <details class=\"faq\">\n        <summary>Are there in-app purchases beyond the $2.99 unlock?<span class=\"ch\">+</span></summary>\n        <p>No. The $2.99 unlock is the only purchase. Future content updates are included.</p>\n      </details>\n      <details class=\"faq\">\n        <summary>What data does Rolligan collect?<span class=\"ch\">+</span></summary>\n        <p>None. Rolligan runs entirely on your device and doesn&apos;t send gameplay data, scores, or personal information to us. See the <a href=\"/privacy\">full privacy policy</a> for details.</p>\n      </details>\n      <details class=\"faq\">\n        <summary>I found a bug. Who do I talk to?<span class=\"ch\">+</span></summary>\n        <p>Email <a href=\"mailto:hello@clarendon.dev\">hello@clarendon.dev</a>. It goes to the engineer who built the app. Replies typically inside one business day \u2014 faster if it&apos;s a real bug.</p>\n      </details>\n    </div>\n  </div>\n</section>\n\n<!-- CTA -->\n<section id=\"download\" style=\"padding: 0 0 120px;\">\n  <div class=\"container\">\n    <div class=\"card-dark reveal\">\n      <div style=\"position: absolute; right: -100px; top: -100px; width: 500px; height: 500px; background: radial-gradient(50% 50% at 50% 50%, color-mix(in srgb, var(--accent) 35%, transparent) 0%, transparent 70%); pointer-events: none;\"></div>\n      <div style=\"display: grid; grid-template-columns: 7fr 5fr; gap: 56px; align-items: center; position: relative;\">\n        <div>\n          <div class=\"eyebrow\" style=\"color: var(--accent-2);\"><span class=\"dot\" style=\"background: var(--accent-2);\"></span> Available now</div>\n          <h2 style=\"margin-top: 14px; color: #fff;\">Get the dice in your hand<span class=\"stop\">.</span></h2>\n          <p style=\"color: var(--on-dark-mute); font-size: 18px; margin-top: 16px; max-width: 44ch;\">Free on the App Store. $2.99 unlock for the deep cut. One purchase covers every device on your Apple ID.</p>\n        </div>\n        <div style=\"display: flex; flex-direction: column; gap: 12px; align-items: flex-start;\">\n          <a href=\"https://rolligan.com\" class=\"btn btn-fill\" style=\"background: #fff; color: var(--ink); box-shadow: none;\">Visit rolligan.com \u2192</a>\n          <a href=\"#\" class=\"btn\" style=\"background: rgba(255,255,255,0.08); color: #fff; border: 1px solid rgba(255,255,255,0.15);\">Download from App Store \u2192</a>\n        </div>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- FOOTER -->\n<footer>\n  <div class=\"container\">\n    <div class=\"dir\">\n      <div class=\"left\">\n        <a href=\"/\" class=\"wordmark\"><span>Clarendon</span><span class=\"dot\"></span></a>\n        <p>An independent iOS studio. One craftsman. Chicago, Illinois \u2014 est. 2026. Clarendon Labs LLC.</p>\n        <a href=\"mailto:hello@clarendon.dev\" class=\"mail\">hello@clarendon.dev \u2192</a>\n      </div>\n      <div>\n        <h5>Studio</h5>\n        <ul>\n          <li><a href=\"/studio\">About</a></li>\n          <li><a href=\"/studio#provenance\">Provenance</a></li>\n          <li><a href=\"/#newsroom\">Newsroom</a></li>\n        </ul>\n      </div>\n      <div>\n        <h5>Catalog</h5>\n        <ul><li><a href='https://gagorder.app'>Gag Order</a></li><li><a href='https://rolligan.com'>Rolligan</a></li><li><a href='https://yulepick.app'>YulePick</a></li></ul>\n      </div>\n      <div>\n        <h5>Help</h5>\n        <ul>\n          <li><a href=\"/support\">Support</a></li>\n          <li><a href=\"/privacy\">Privacy</a></li>\n          <li><a href=\"/terms\">Terms</a></li>\n        </ul>\n      </div>\n      <div>\n        <h5>Elsewhere</h5>\n        <ul>\n          <li><a href=\"#\">App Store</a></li>\n          <li><a href=\"https://rolligan.com\">rolligan.com</a></li>\n          <li><a href=\"#\">RSS</a></li>\n        </ul>\n      </div>\n    </div>\n    <div class=\"colophon\">\n      <span>\u00a9 2026 Clarendon Labs LLC \u00b7 4801 N. Clarendon Ave., Chicago, IL 60640</span>\n      <div class=\"links\">\n        <a href=\"/privacy\">Privacy</a>\n        <a href=\"/terms\">Terms</a>\n        <a href=\"/support\">Support</a>\n      </div>\n    </div>\n  </div>\n</footer>\n\n\n"

